import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  FiShield, 
  FiArrowLeft, 
  FiUsers, 
  FiCalendar, 
  FiDollarSign,
  FiTrendingUp,
  FiUserPlus,
  FiSettings,
  FiLogOut,
  FiBarChart,
  FiCheckCircle,
  FiClock,
  FiXCircle,
  FiEye,
  FiPackage,
  FiGift,
  FiX,
  FiInfo,
  FiGrid,
  FiTag,
  FiPlus,
  FiTrash2,
  FiCopy,
  FiSave,
  FiEdit,
  FiMapPin
} from 'react-icons/fi';
import { useAuth } from '../context/AuthContext';
import { Booking, Employee, ContactQuery } from '../types';
import { apiService } from '../services/api';
import { API_ENDPOINTS } from '../config/api';
import { useQuery } from 'react-query';
import toast from 'react-hot-toast';

const AdminDashboard: React.FC = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isAddServiceModalOpen, setIsAddServiceModalOpen] = useState(false);
  const [isAddOfferModalOpen, setIsAddOfferModalOpen] = useState(false);
  const [isAddLocationModalOpen, setIsAddLocationModalOpen] = useState(false);
  const [bookingsTab, setBookingsTab] = useState<'all' | 'pending' | 'accepted' | 'completed'>('all');
  const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);
  coyenst [showBookingModal, setShowBookingModal] = useState(false);
  const [assignTechId, setAssignTechId] = useState<string>('');
  const [assignLoading, setAssignLoading] = useState(false);
  const [verifyLoading, setVerifyLoading] = useState(false);
  const [queryViewMode, setQueryViewMode] = useState<'table' | 'card'>('table');
  const [showQueryModal, setShowQueryModal] = useState(false);
  const [showRespondModal, setShowRespondModal] = useState(false);
  const [selectedQuery, setSelectedQuery] = useState<any>(null);
  const [respondText, setRespondText] = useState('');
  const [respondLoading, setRespondLoading] = useState(false);
  const [querySearch, setQuerySearch] = useState('');
  const [showFilterDropdown, setShowFilterDropdown] = useState(false);
  const [statusFilter, setStatusFilter] = useState('all');
  const [dateFilter, setDateFilter] = useState('all');

  // Add state for service details modal
  const [selectedService, setSelectedService] = useState<any>(null);
  const [serviceDetailsModalOpen, setServiceDetailsModalOpen] = useState(false);
  const [serviceDetailsData, setServiceDetailsData] = useState<any>(null);
  const [serviceDetailsLoading, setServiceDetailsLoading] = useState(false);

  // Add state for offer details modal
  const [selectedOffer, setSelectedOffer] = useState<any>(null);
  const [offerDetailsModalOpen, setOfferDetailsModalOpen] = useState(false);

  // Add state for service editing
  const [editingServiceTypes, setEditingServiceTypes] = useState<any[]>([]);
  const [originalServiceTypes, setOriginalServiceTypes] = useState<any[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Add state for edit service details modal
  const [editServiceModalOpen, setEditServiceModalOpen] = useState(false);
  const [editServiceForm, setEditServiceForm] = useState({
    service_name: '',
    description: '',
    locations: ''
  });
  const [editServiceLoading, setEditServiceLoading] = useState(false);

  // Add state for add offer modal
  const [addOfferModalOpen, setAddOfferModalOpen] = useState(false);
  const [addOfferForm, setAddOfferForm] = useState({
    offer_name: '',
    coupon_number: '',
    offer_starts_on: '',
    expires_on: '',
    offer_percentage: ''
  });
  const [addOfferLoading, setAddOfferLoading] = useState(false);
  const [selectedOfferFile, setSelectedOfferFile] = useState<File | null>(null);
  const [offerBannerPreview, setOfferBannerPreview] = useState<string | null>(null);

  // Add state for offers search and filter
  const [offersSearchTerm, setOffersSearchTerm] = useState('');
  const [offersStatusFilter, setOffersStatusFilter] = useState('all');
  const [offersDateFilter, setOffersDateFilter] = useState('all');

  // Add state for services search and filter
  const [servicesSearchTerm, setServicesSearchTerm] = useState('');

  // Add state for employees search and filter
  const [employeesSearchTerm, setEmployeesSearchTerm] = useState('');
  const [employeesServiceTypeFilter, setEmployeesServiceTypeFilter] = useState('all');
  // Add state for bookings search and filter
  const [bookingsSearchTerm, setBookingsSearchTerm] = useState('');
  const [bookingsStatusFilter, setBookingsStatusFilter] = useState('all');

  // Add state for add service modal
  const [addServiceModalOpen, setAddServiceModalOpen] = useState(false);
  const [addServiceForm, setAddServiceForm] = useState({
    service_name: '',
    description: ''
  });
  const [addServiceLoading, setAddServiceLoading] = useState(false);
  const [addServiceImage, setAddServiceImage] = useState<File | null>(null);
  const [addServiceImagePreview, setAddServiceImagePreview] = useState<string | null>(null);

  // Handle image selection
  const handleAddServiceImage = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setAddServiceImage(file);
      const reader = new FileReader();
      reader.onload = (e) => setAddServiceImagePreview(e.target?.result as string);
      reader.readAsDataURL(file);
    }
  };
  const clearAddServiceImage = () => {
    setAddServiceImage(null);
    setAddServiceImagePreview(null);
    const fileInput = document.getElementById('add-service-image-input') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Add service submit
  const submitAddService = async () => {
    if (!addServiceForm.service_name.trim()) {
      toast.error('Service name is required');
      return;
    }
    setAddServiceLoading(true);
    try {
      const formData = new FormData();
      formData.append('service_name', addServiceForm.service_name);
      formData.append('description', addServiceForm.description);
      if (addServiceImage) formData.append('service_image', addServiceImage);
      // Optionally: formData.append('locations', '[]');
      const response = await apiService.post('add_service.php', formData);
      const responseData = response.data as any;
      if (responseData.status === 'success') {
        toast.success('Service added successfully');
        setAddServiceModalOpen(false);
        setAddServiceForm({ service_name: '', description: '' });
        setAddServiceImage(null);
        setAddServiceImagePreview(null);
        window.location.reload();
      } else {
        toast.error(responseData.message || 'Failed to add service');
      }
    } catch (error) {
      toast.error('Failed to add service');
    } finally {
      setAddServiceLoading(false);
    }
  };

  // No strict user.id or user.name checks here; just rely on ProtectedRoute
  const sessionId = localStorage.getItem('sessionId');
  // Fetch dashboard data
  const { data: bookingsData, isLoading: bookingsLoading } = useQuery(
    'admin-bookings',
    () => apiService.get<Booking[]>(API_ENDPOINTS.ADMIN_ORDERS),

    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load bookings');
      }
    }
  );

  const { data: employeesData, isLoading: employeesLoading } = useQuery(
    'employees',
    () => apiService.get<Employee[]>(API_ENDPOINTS.GET_TECHNICIANS),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load employees');
      }
    }
  );

  const { data: queriesData, isLoading: queriesLoading } = useQuery(
    'contact-queries',
    () => apiService.get<ContactQuery[]>(API_ENDPOINTS.ADMIN_CONTACT_QUERIES),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load contact queries');
      }
    }
  );

  const { data: servicesData, isLoading: servicesLoading } = useQuery(
    'services',
    () => apiService.get<any>(API_ENDPOINTS.FETCH_SERVICES),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load services');
      }
    }
  );

  const { data: offersData, isLoading: offersLoading } = useQuery(
    'offers',
    () => apiService.get<any>(API_ENDPOINTS.FETCH_OFFERS),
    {
      retry: 1,
      onError: (error) => {
        toast.error('Failed to load offers');
      }
    }
  );

  // Combine bookings arrays from API response (pending, completed, accepted)
  const bookingsDataAny = bookingsData as any;
  const bookings = [
    ...(bookingsDataAny?.orders?.pending || []),
    ...(bookingsDataAny?.orders?.completed || []),
    ...(bookingsDataAny?.orders?.accepted || [])
  ];

  // Sort bookings by service_date descending (latest first)
  const sortedBookings = bookings.sort((a, b) => new Date(b.service_date).getTime() - new Date(a.service_date).getTime());

  // Employees: use data array from API response and map to UI model
  const employeesDataAny = employeesData as any;
  const employees = (employeesDataAny?.data || []).map((emp: any) => ({
    id: emp.technician_id,
    name: emp.employee_name,
    email: emp.email,
    mobile: emp.phone_number,
    serviceType: emp.service_type,
    address: emp.address,
    idProof: emp.id_proof,
  }));

  // Combine queries arrays if nested (adjust as needed)
  const queriesDataAny = queriesData as any;
  const queries = queriesDataAny?.queries || queriesDataAny?.data?.queries || [];

  // Calculate statistics
  const totalBookings = bookings.length;
  const pendingBookings = bookings.filter(b => b.status === 'pending').length;
  const completedBookings = bookings.filter(b => b.status === 'completed').length;
  const totalRevenue = bookings.reduce((sum, b) => sum + b.total_amount, 0);
  const pendingQueries = queries.filter((q: any) => q.status === 'pending').length;

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed':
        return 'bg-green-100 text-green-800';
      case 'accepted':
        return 'bg-blue-100 text-blue-800';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      case 'cancelled':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const statsCards = [
    {
      title: 'Total Bookings',
      value: totalBookings,
      icon: FiCalendar,
      color: 'bg-blue-500',
    },
    {
      title: 'Pending Bookings',
      value: pendingBookings,
      icon: FiClock,
      color: 'bg-yellow-500',
    },
    {
      title: 'Total Revenue',
      value: `₹${totalRevenue.toLocaleString()}`,
      icon: FiDollarSign,
      color: 'bg-green-500',
    },
    {
      title: 'Active Employees',
      value: employees.length,
      icon: FiUsers,
      color: 'bg-purple-500',
    }
  ];

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center space-x-4">
              <button
                onClick={() => window.history.back()}
                className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
              >
                <FiArrowLeft className="w-5 h-5" />
              </button>
              <div className="w-10 h-10 bg-teal-600 rounded-lg flex items-center justify-center">
                <FiShield className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-semibold text-gray-900">NPC Admin</h1>
                <p className="text-sm text-gray-500">Administration Panel</p>
              </div>
            </div>

            <div className="flex items-center space-x-4">
              <div className="text-right">
                <p className="text-sm font-medium text-gray-900">Welcome,</p>
                <p className="text-sm text-gray-500">{user?.name || 'Admin'}</p>
              </div>
              <button
                onClick={handleLogout}
                className="p-2 text-gray-400 hover:text-gray-600 transition-colors"
              >
                <FiLogOut className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
        >
          {/* Page Header */}
          <div className="mb-8">
            <h2 className="text-3xl font-bold text-gray-900 mb-2">Admin Dashboard</h2>
            <p className="text-gray-600">Manage your business operations</p>
          </div>

          {/* Statistics Cards */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
            {statsCards.map((stat, index) => (
              <motion.div
                key={stat.title}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.3, delay: index * 0.1 }}
                className="bg-white rounded-lg shadow-sm p-6"
              >
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm font-medium text-gray-600">{stat.title}</p>
                    <p className="text-2xl font-bold text-gray-900">{stat.value}</p>
                  </div>
                  <div className={`w-12 h-12 ${stat.color} rounded-lg flex items-center justify-center`}>
                    <stat.icon className="w-6 h-6 text-white" />
                  </div>
                </div>
              </motion.div>
            ))}
          </div>

          {/* Tab Navigation */}
          <div className="mb-6">
            <div className="border-b border-gray-200">
              <nav className="-mb-px flex space-x-8">
                                 {[
                   { id: 'overview', label: 'Overview', icon: FiBarChart },
                  { id: 'bookings', label: 'Bookings', icon: FiCalendar },
                  { id: 'employees', label: 'Employees', icon: FiUsers },
                  { id: 'queries', label: 'Contact Queries', icon: FiSettings }
                ].map((tab) => (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)}
                    className={`py-2 px-1 border-b-2 font-medium text-sm transition-colors ${
                      activeTab === tab.id
                        ? 'border-teal-500 text-teal-600'
                        : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                    }`}
                  >
                    <tab.icon className="inline w-4 h-4 mr-1" />
                    {tab.label}
                  </button>
                ))}
              </nav>
            </div>
          </div>

          {/* Tab Content */}
          {activeTab === 'overview' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* Recent Bookings */}
              <div className="bg-white rounded-lg shadow-sm p-6">
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Recent Bookings</h3>
                {bookingsLoading ? (
                  <div className="flex justify-center py-8">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                  </div>
                ) : bookings.length === 0 ? (
                  <p className="text-gray-500 text-center py-8">No bookings found</p>
                ) : (
                  <div className="space-y-3">
                    {bookings.slice(0, 5).map((booking) => (
                      <div key={booking.booking_id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                        <div>
                          <p className="font-medium text-gray-900">{booking.service_name}</p>
                          <p className="text-sm text-gray-600">{formatDate(booking.service_date)}</p>
                        </div>
                        <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(booking.status)}`}>
                          {booking.status}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Pending Queries */}
              <div className="bg-white rounded-lg shadow-sm p-6">
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Pending Contact Queries</h3>
                {queriesLoading ? (
                  <div className="flex justify-center py-8">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-teal-600"></div>
                  </div>
                ) : pendingQueries === 0 ? (
                  <p className="text-gray-500 text-center py-8">No pending queries</p>
                ) : (
                  <div className="space-y-3">
                    {queries.filter((q: any) => q.status === 'pending').slice(0, 5).map((query: any) => (
                      <div key={query.query_id} className="p-3 bg-gray-50 rounded-lg">
                        <p className="font-medium text-gray-900">{query.subject}</p>
                        <p className="text-sm text-gray-600">{query.first_name} {query.last_name}</p>
                        <p className="text-xs text-gray-500">{formatDate(query.created_at)}</p>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}

          {activeTab === 'bookings' && (
            <div className="bg-white rounded-lg shadow-sm overflow-hidden">
              <div className="px-6 py-4 border-b border-gray-200">
                <h3 className="text-lg font-semibold text-gray-900">All Bookings</h3>
              </div>
              {bookingsLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Service
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Date
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Amount
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Status
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {bookings.map((booking) => (
                        <tr key={booking.booking_id}>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm font-medium text-gray-900">{booking.service_name}</div>
                            <div className="text-sm text-gray-500">{booking.booking_id}</div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            {formatDate(booking.service_date)}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            ₹{booking.total_amount}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(booking.status)}`}>
                              {booking.status}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}

          {activeTab === 'employees' && (
            <div className="bg-white rounded-lg shadow-sm overflow-hidden">
              <div className="px-6 py-4 border-b border-gray-200 flex justify-between items-center">
                <h3 className="text-lg font-semibold text-gray-900">Employees</h3>
                <button className="btn btn-primary text-sm">
                  <FiUserPlus className="w-4 h-4 mr-2" />
                  Add Employee
                </button>
              </div>
              {employeesLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Employee
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Contact
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Service Type
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Status
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {employees.map((employee: any) => (
                        <tr key={employee.id}>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm font-medium text-gray-900">{employee.name}</div>
                            <div className="text-sm text-gray-500">{employee.email}</div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            {employee.mobile}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            {employee.serviceType}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className="px-2 py-1 rounded-full text-xs font-medium bg-green-100 text-green-800">
                              Active
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}

          {activeTab === 'queries' && (
            <div className="bg-white rounded-lg shadow-sm overflow-hidden">
              <div className="px-6 py-4 border-b border-gray-200">
                <h3 className="text-lg font-semibold text-gray-900">Contact Queries</h3>
              </div>
              {queriesLoading ? (
                <div className="flex justify-center py-12">
                  <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Query
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Contact
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Date
                        </th>
                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                          Status
                        </th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                      {queries.map((query: any) => (
                        <tr key={query.query_id}>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm font-medium text-gray-900">{query.subject}</div>
                            <div className="text-sm text-gray-500 truncate max-w-xs">{query.message}</div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="text-sm text-gray-900">{query.first_name} {query.last_name}</div>
                            <div className="text-sm text-gray-500">{query.email}</div>
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                            {formatDate(query.created_at)}
                          </td>
                          <td className="px-6 py-4 whitespace-nowrap">
                            <span className={`px-2 py-1 rounded-full text-xs font-medium ${
                              query.status === 'pending' ? 'bg-yellow-100 text-yellow-800' : 'bg-green-100 text-green-800'
                            }`}>
                              {query.status}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          )}
        </motion.div>
      </div>
    </div>
  );
};

export default AdminDashboard;
